    public static Money getProperty(MaandTotaal1 mt1, MoneyKey key) {
        if (key instanceof RekenBasisRszKey) {
            return getPropertyBasisRsz(mt1, (RekenBasisRszKey) key);
        } else if (key instanceof RekenBrutoKey) {
            return getPropertyBruto(mt1, (RekenBrutoKey) key);
        } else if (key instanceof RekenRszKey) {
            return getPropertyRsz(mt1, (RekenRszKey) key);
        } else if (key instanceof RekenPatronaalRszKey) {
            return getPropertyPatronaalRsz(mt1, (RekenPatronaalRszKey) key);
        } else if (key instanceof RekenPatronaalPriveRszKey) {
            return getPropertyPatronaalPriveRsz(mt1, (RekenPatronaalPriveRszKey) key);
        } else if (key instanceof BelastbaarAchterstalKey) {
            return getPropertyBelastbaarAchterstal(mt1, (BelastbaarAchterstalKey) key);
        } else if (key instanceof BelastbaarKey) {
            return getPropertyBelastbaar(mt1, (BelastbaarKey) key);
        } else if (key instanceof RekenBvKey) {
            return getPropertyBv(mt1, (RekenBvKey) key);
        } else if (key instanceof RekenNettoKey) {
            throw new NoUniqueFieldToKeyMappingException();
        } else if (key instanceof RekenBbKey) {
            return getPropertyBelastbaarSpeciaal(mt1, (RekenBbKey) key);
        } else {
            throw new UnsupportedOperationException();
        }
    }

    public static void setProperty(Money bedrag, MaandTotaal1 mt1, MoneyKey key) {
        if (key instanceof RekenBasisRszKey) {
            setPropertyBasisRsz(bedrag, mt1, (RekenBasisRszKey) key);
        } else if (key instanceof RekenBrutoKey) {
            setPropertyBruto(bedrag, mt1, (RekenBrutoKey) key);
        } else if (key instanceof RekenRszKey) {
            setPropertyRsz(bedrag, mt1, (RekenRszKey) key);
        } else if (key instanceof RekenPatronaalRszKey) {
            setPropertyPatronaalRsz(bedrag, mt1, (RekenPatronaalRszKey) key);
        } else if (key instanceof RekenPatronaalPriveRszKey) {
            setPropertyPatronaalPriveRsz(bedrag, mt1, (RekenPatronaalPriveRszKey) key);
        } else if (key instanceof BelastbaarAchterstalKey) {
            setPropertyBelastbaarAchterstal(bedrag, mt1, (BelastbaarAchterstalKey) key);
        } else if (key instanceof BelastbaarKey) {
            setPropertyBelastbaar(bedrag, mt1, (BelastbaarKey) key);
        } else if (key instanceof RekenBvKey) {
            setPropertyBv(bedrag, mt1, (RekenBvKey) key);
        } else if (key instanceof RekenNettoKey) {
            throw new NoUniqueFieldToKeyMappingException();
        } else if (key instanceof RekenBbKey) {
            setPropertyBelastbaarSpeciaal(bedrag, mt1, (RekenBbKey) key);
        } else {
            throw new UnsupportedOperationException();
        }
    }

