public static Money maakElementSomBruto(List<RekenElement> elementen) {
    Money brutoBestaand = Money.ZERO;
    for (RekenElement element : elementen) {
        brutoBestaand = brutoBestaand.add(element.getBruto());
    }
    return brutoBestaand;
}

public static Money maakElementSomBasisSocialeInhoudingen(List<RekenElement> elementen) {
    Money basisSiBestaand = Money.ZERO;
    for (RekenElement element : elementen) {
        basisSiBestaand = basisSiBestaand.add(element.getBasisSocialeInhoudingen());
    }
    return basisSiBestaand;
}

public static Money maakInhoudingVerschil(Money bedrag, List<Inhouding> inhoudingen) {
    Money bedragBestaand = Money.ZERO;
    for (Inhouding inhouding : inhoudingen) {
        bedragBestaand = bedragBestaand.add(inhouding.getBedrag());
    }
    return bedrag.subtract(bedragBestaand);
}

