    public static <T> void maakGesommeerdObject(T somObj, List<T> lijst) {
        initialiseerMoneyVelden(somObj);
        for (Method setMethod : somObj.getClass().getMethods()) {
            if (setMethod.getName().startsWith("set") && setMethod.getParameterTypes().length == 1 && setMethod.getParameterTypes()[0] == Money.class) {
                try {
                    String getName = 'g' + setMethod.getName().substring(1);
                    Method getMethod = somObj.getClass().getMethod(getName);
                    Money som = (Money) getMethod.invoke(somObj);
                    for (Object object : lijst) {
                        Money bedrag = (Money) getMethod.invoke(object);
                        som = som.add(bedrag);
                    }
                    setMethod.invoke(somObj, som);
                } catch (ReflectiveOperationException e) {
                    throw new MessageException("Reflection FAIL", e);
                }
            }
        }
    }

    public static <T> void substractMoneyFields(T substractee, T subtractor) {
        for (Method setMethod : substractee.getClass().getMethods()) {
            if (setMethod.getName().startsWith("set") && setMethod.getParameterTypes().length == 1 && setMethod.getParameterTypes()[0] == Money.class) {
                try {
                    String getName = "g" + setMethod.getName().substring(1);
                    Method getMethod = substractee.getClass().getMethod(getName);
                    Money bedrag = (Money) getMethod.invoke(substractee);
                    Money aftrok = (Money) getMethod.invoke(subtractor);
                    Money diff = bedrag.subtract(aftrok);
                    setMethod.invoke(substractee, diff);
                } catch (ReflectiveOperationException e) {
                    throw new MessageException("Reflection FAIL", e);
                }
            }
        }
    }

    public static void initialiseerMoneyVelden(Object object) {
        for (Method method : object.getClass().getMethods()) {
            if (method.getName().startsWith("set") && method.getParameterTypes().length == 1 && method.getParameterTypes()[0] == Money.class) {
                try {
                    method.invoke(object, Money.ZERO);
                } catch (ReflectiveOperationException e) {
                    throw new MessageException("Reflection FAIL", e);
                }
            }
        }
    }

    public static boolean checkMoneyFieldsAreZero(Object object) {
        boolean allZeroes = true;
        for (Method method : object.getClass().getMethods()) {
            if (method.getName().startsWith("get") && method.getParameterTypes().length == 0 && method.getReturnType() == Money.class) {
                try {
                    Money moneyVeld = (Money) method.invoke(object);
                    allZeroes = moneyVeld != null && moneyVeld.signum() == 0;
                } catch (ReflectiveOperationException e) {
                    throw new MessageException("Reflection FAIL", e);
                }
                if (!allZeroes) {
                    break;
                }
            }
        }
        return allZeroes;
    }

    public static MaandTotaal1 maakGesommeerdMaandtotaal(List<MaandTotaal1> opdrachtBestaanden) {
        MaandTotaal1 somMt1 = new MaandTotaal1PO();
        ReflectionUtil.maakGesommeerdObject(somMt1, opdrachtBestaanden);

        MaandTotaal2 somMt2 = new MaandTotaal2PO();
        somMt1.setMaandTotaal2(somMt2);
        List<MaandTotaal2> mt2Lijst = getMaandTotaal2Lijst(opdrachtBestaanden);

        ReflectionUtil.maakGesommeerdObject(somMt2, mt2Lijst);

        MaandTotaal3 somMt3 = new MaandTotaal3PO();
        somMt1.setMaandTotaal3(somMt3);
        List<MaandTotaal3> mt3Lijst = getMaandTotaal3Lijst(opdrachtBestaanden);

        ReflectionUtil.maakGesommeerdObject(somMt3, mt3Lijst);

        return somMt1;
    }

    public static List<MaandTotaal2> getMaandTotaal2Lijst(List<MaandTotaal1> maandtotalen) {
